import React, { type ChangeEvent, type MouseEvent, useState } from 'react';

import { IconButton } from '../IconButton';
import type { ControlledSearchProps } from './Search.types';

export const Controlled = ({
	inputRef,
	onChange,
	dataTestId,
	dataTestIconId,
	iconButton,
	maskConfig,
	...props
}: ControlledSearchProps) => {
	const [value, setValue] = useState('');

	const { onClick, ...rest } = iconButton;

	const handleChange = (event: ChangeEvent<HTMLInputElement>): void => {
		setValue(event.target.value);
		onChange?.(event);
	};

	const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
		onClick?.(event);
		setValue('');
	};

	return (
		<>
			<input ref={inputRef} value={value} data-testid={dataTestId} onChange={handleChange} {...props} />
			{value && <IconButton {...rest} dataTestId={dataTestIconId} onClick={handleClick} />}
		</>
	);
};
